import pygameimport matplotlib.pyplot as pltimport timefrom api_client import fetch_datafrom cache_manager import MarketDataCachefrom chart_renderer import draw_graphfrom ui import create_buttons, draw_buttons, draw_tooltipWIDTH = 1100HEIGHT = 700LIGHT_MODE_BG = (255, 255, 255)DARK_MODE_BG = (0, 0, 0)BUTTON_COLOR = (0, 70, 180)TEXT_COLOR = (255, 255, 255)REFRESH_COOLDOWN_SECONDS = 15TIMEFRAME_MAP = {    "1 Day": 1,    "1 Week": 7,    "1 Month": 30,    "1 Year": 365,    "Max": "max",}def get_graph_for_timeframe(label, dark_mode, cache):    """    Load data and graph for the selected timeframe.    Uses caching so the app does not keep repeating API calls.    """    days = TIMEFRAME_MAP.get(label, 30)    df = cache.get_data(label)    if df is None:        df = fetch_data(days)        cache.set_data(label, df)    plot_type = "line" if label == "Max" else "candle"    graph = cache.get_graph(label, dark_mode)    if graph is None:        graph = draw_graph(            df,            plot_type=plot_type,            dark_mode=dark_mode,        )        cache.set_graph(label, dark_mode, graph)    return graphdef main():    pygame.init()    screen = pygame.display.set_mode((WIDTH, HEIGHT))    pygame.display.set_caption("Bitcoin Price Chart Visualiser")    dark_mode = False    background_color = LIGHT_MODE_BG    buttons = create_buttons(WIDTH, HEIGHT)    cache = MarketDataCache()    timeframe_label = "1 Day"    graph = get_graph_for_timeframe(timeframe_label, dark_mode, cache)    clock = pygame.time.Clock()    running = True    last_refresh_time = 0    while running:        try:            for event in pygame.event.get():                if event.type == pygame.QUIT:                    running = False                elif event.type == pygame.KEYDOWN:                    if event.key == pygame.K_ESCAPE:                        running = False                    # Press R to refresh the current timeframe.                                        elif event.key == pygame.K_r:                         current_time = time.time()                                                 if current_time - last_refresh_time < REFRESH_COOLDOWN_SECONDS:                             print("Please wait before refreshing again.")                             continue                                                 print("Refreshing data...")                                                 days = TIMEFRAME_MAP.get(timeframe_label, 30)                         fresh_df = fetch_data(days)                                                 if fresh_df is not None and not fresh_df.empty:                             cache.set_data(timeframe_label, fresh_df)                             cache.clear_graphs()                                                         graph = get_graph_for_timeframe(                                 timeframe_label,                                 dark_mode,                                 cache                                 )                             last_refresh_time = current_time                             print("Refresh successful.")                                                     else:                             print("Refresh failed or returned no data. Keeping the existing chart.")                elif event.type == pygame.MOUSEBUTTONDOWN:                    mouse_pos = pygame.mouse.get_pos()                    for label, rect in buttons.items():                        if rect.collidepoint(mouse_pos):                            if label == "Dark Mode":                                dark_mode = not dark_mode                                background_color = (                                    DARK_MODE_BG if dark_mode else LIGHT_MODE_BG                                )                                graph = get_graph_for_timeframe(                                    timeframe_label,                                    dark_mode,                                    cache                                )                            else:                                timeframe_label = label                                graph = get_graph_for_timeframe(                                    timeframe_label,                                    dark_mode,                                    cache                                )            screen.fill(background_color)            graph_rect = graph.get_rect(center=(WIDTH // 2, HEIGHT // 2 - 40))            screen.blit(graph, graph_rect.topleft)            draw_buttons(screen, buttons, BUTTON_COLOR, TEXT_COLOR)            # Tooltip            mouse_x, mouse_y = pygame.mouse.get_pos()            df = cache.get_data(timeframe_label)            if (                graph_rect.left <= mouse_x <= graph_rect.right                and graph_rect.top <= mouse_y <= graph_rect.bottom                and df is not None                and not df.empty            ):                relative_x = mouse_x - graph_rect.left                date_index = min(                    max(0, relative_x * len(df) // graph_rect.width),                    len(df) - 1,                )                date = df.index[date_index]                price = df["Close"].iloc[date_index]                tooltip_text = f"{date.strftime('%Y-%m-%d %H:%M')}: ${price:.2f}"                draw_tooltip(                    screen,                    mouse_x,                    mouse_y,                    tooltip_text,                    dark_mode,                )            pygame.display.flip()            clock.tick(30)        except Exception as error:            print(f"Unexpected error: {error}")            running = False    pygame.quit()    plt.close("all")if __name__ == "__main__":    main()